INSERT INTO users(first_name, last_name, user_name, user_type, mhswitch, dob, email, password, title, about, p_img, b_img, category, sub_category, payment, patreon, wp_title, webpage, rsvp_attend, rsvp_perform,verified) VALUES('Bunny', 'Holmes', 'The Vespertine Circus',"host",false,"1988-08-23",'ze23vbu@gmail.com', '3dca3a56d395808ac914e892231e0a3ae7e4c7fe',"An Independent interdisciplinary circus and performing arts troupe.",'Are you looking for an unforgettable show? Step right up! You’ve come to the right place! We aim to inspire – to draw audiences into a curious and unlikely world, full of humor and wonder. The Vespertine Circus performs across the continental United States! Based out of Oakland, CA. We are a small collection of ambitious oddballs on a quest to spread joy and absurdity. Our troupe is inspired by both the iconic and small, traveling, family-circuses that first swept across America around the late 1800s; and the theatrical, dance-infused, animal-free, indoor contemporary circus movement. We weave circus arts into the context of narrative theater, with characters you can relate to.',"http://www.vespertinecircus.com/wp-content/uploads/2011/12/hingetroupe1crop-1024x1024.jpg","http://www.vespertinecircus.com/wp-content/uploads/2020/05/wp2174026-metal-texture-wallpapers.jpg","performance","play",'paymentlink','Patreon link','Learn more about us here:', 'http://www.vespertinecircus.com/', '1.Mondo! blaa.4-23-20.12:23pm.2:23pm','1.Mondo! blaa.4-23-20.12:23pm.2:23pm', true);
INSERT INTO users(first_name, last_name, user_name, user_type, mhswitch, dob, email, password, title, about, p_img, b_img, category, sub_category, payment, patreon, wp_title, webpage, rsvp_attend, rsvp_perform,verified) VALUES('Scott', 'Levkoff', "Master Mondo's Midway", "host",false,"1988-08-23", 'zevub4u@gmail.com', '3dca3a56d395808ac914e892231e0a3ae7e4c7fe',"WE CREATE SPECTACULAR AND ENGAGING EVENTS -- AND COMMUNITY!","We create immersive spectacles and live social gaming experiences that bring people together. We're excited to create a unique and amazing experience for you. Mystic Midway can design a custom event just for you -- whether you need an unforgettable party, mind-blowing team-building quests, or something entirely new. Our events work for groups as small as 75 and as large as 10,000. We host events at our locations, or can create one for yours. We build experiences that last anywhere from a few hours to a few days.","https://images.squarespace-cdn.com/content/v1/585982cef5e2311e1a962340/1515812415919-A9BLD5P6NX5E3TCLO0D1/ke17ZwdGBToddI8pDm48kN5krWEhV78lvJ_TRla4yYQUqsxRUqqbr1mOJYKfIPR7LoDQ9mXPOjoJoqy81S2I8PaoYXhp6HxIwZIk7-Mi3Tsic-L2IOPH3Dwrhl-Ne3Z2zLurNxEa9MLS9lV0wNQgK0YIzZD5uHxYVqxgBYcaImebtxPRH917Fz9Qv_NunPol/IMG_1555.jpg?format=500w","https://www.midwayville.com/?fbclid=IwAR35EhJJgqlJf0nrOUbVL-CyfqUkeoSwduF4qWewkfiyyDjZqOrvUvM-SUw#/midway-at-winchester-2018/","performance","variety",'paymentlink','Patreon link','Find out more about us here:', 'https://playable.agency/', '1.Mondo! blaa.4-23-20.12:23pm.2:23pm','1.Mondo! blaa.4-23-20.12:23pm.2:23pm', true);
